mapper.sql:
select l.id as linkId, l.visit_kind as visitKind, l.mirror_row_id as mirrorRowId, l.alloc_qty as allocQty, ifnull(l.returned_qty, 0) as returnedQty, l.dept_batch_consume_entry_id as deptBatchConsumeEntryId, l.in_hospital_code as inHospitalCode, ifnull(l.confirm_status, 0) as confirmStatus, l.confirm_id as confirmId, c.confirm_no as confirmNo, in_bill.bill_no as inboundBillNo, out_bill.bill_no as outboundBillNo, th_bill.bill_no as returnGoodsBillNo, tk_bill.bill_no as returnDepotBillNo, ifnull(l.instant_io_audit_status, 0) as instantIoAuditStatus, l.instant_io_audit_by as instantIoAuditBy, l.instant_io_audit_time as instantIoAuditTime, c.confirm_by as confirmBy, c.confirm_time as confirmTime, t.create_time as consumeCreateTime, cast(t.audit_date as datetime) as consumeAuditDate, () as consumeAuditTime, t.trace_no as consumeBillNo, te.id as consumeEntryId, te.material_id as materialId, te.material_name as materialName, te.charge_price as unitPrice, coalesce(l.alloc_qty, te.quantity) as entryQty, case when te.charge_price is not null and coalesce(l.alloc_qty, te.quantity) is not null then te.charge_price * coalesce(l.alloc_qty, te.quantity) else null end as amt, cast(te.supplier_id as char) as supplierId, sup.name as supplierName, te.batch_no as batchNo, as departmentId, d.name as departmentName, coalesce(nullif(trim(coalesce(inp.dept_name, outp.clinic_name)), ''), ad.name) as orderingDeptName, coalesce(nullif(trim(coalesce(inp.exec_dept_name, outp.exec_dept_name)), ''), ed.name) as execDeptName, coalesce(inp.patient_name, outp.patient_name) as patientName, coalesce(inp.inpatient_no, outp.outpatient_no) as visitNo, coalesce(inp.his_inpatient_charge_id, outp.his_outpatient_charge_id) as hisChargeId, coalesce(inp.charge_item_id, outp.charge_item_id) as chargeItemId, coalesce(inp.item_name, outp.item_name) as itemName, coalesce( nullif(trim(inp.spec_model), ''), nullif(trim(outp.spec_model), ''), (select cm.speci from fd_material cm where cm.tenant_id = l.tenant_id and trim(cm.his_charge_item_id) = trim(coalesce(inp.charge_item_id, outp.charge_item_id)) and (cm.del_flag = 0 or cm.del_flag is null) order by cm.id limit 1) ) as itemSpec, (select cm.model from fd_material cm where cm.tenant_id = l.tenant_id and trim(cm.his_charge_item_id) = trim(coalesce(inp.charge_item_id, outp.charge_item_id)) and (cm.del_flag = 0 or cm.del_flag is null) order by cm.id limit 1) as itemModel, coalesce(nullif(trim(te.specification), ''), m.speci) as materialSpeci, coalesce(nullif(trim(te.model), ''), m.model) as materialModel, coalesce(nullif(trim(gdi.material_no), ''), nullif(trim(gse.batch_number), ''), nullif(trim(goe.batch_number), ''), te.batch_no) as batchNumber, coalesce(gdi.material_date, gse.begin_time, goe.begin_time) as productionDate, coalesce(goe.end_time, gse.end_time, te.expiry_date) as endTime, coalesce(nullif(trim(te.manufacturer), ''), ff.factory_name) as factoryName, coalesce(nullif(trim(te.certificate_no), ''), m.register_no) as registerNo
and = #{departmentId}
and ( t.apply_dept_id = #{orderingDepartmentId} or exists ( select 1 from fd_department od where od.id = #{orderingDepartmentId} and od.tenant_id = l.tenant_id and ( (l.visit_kind = 'INPATIENT' and inp.id is not null and trim(od.his_id) = trim(inp.dept_code)) or (l.visit_kind = 'OUTPATIENT' and outp.id is not null and trim(od.his_id) = trim(outp.clinic_code)) ) ) )
and ( t.exec_dept_id = #{execDepartmentId} or exists ( select 1 from fd_department xd where xd.id = #{execDepartmentId} and xd.tenant_id = l.tenant_id and trim(xd.his_id) = trim(coalesce(inp.exec_dept_id, outp.exec_dept_id)) ) )
and ifnull(l.confirm_status, 0) = #{confirmStatus}
and ifnull(l.confirm_status, 0) = 1 and ifnull(l.instant_io_audit_status, 0) = 1 and ifnull(l.returned_qty, 0) > 0 and th_bill.id is null and tk_bill.id is null
and ifnull(l.instant_io_audit_status, 0) = #{instantIoAuditStatus}
and () >= #{beginConsumeAuditTime}
and () <= #{endConsumeAuditTime}
and coalesce(inp.patient_name, outp.patient_name) like concat('%', #{patientName}, '%')
and coalesce(inp.inpatient_no, outp.outpatient_no) like concat('%', #{visitNo}, '%')
and ( (l.visit_kind = 'INPATIENT' and inp.his_inpatient_charge_id like concat('%', #{hisChargeId}, '%')) or (l.visit_kind = 'OUTPATIENT' and outp.his_outpatient_charge_id like concat('%', #{hisChargeId}, '%')) )
and coalesce(inp.charge_item_id, outp.charge_item_id) like concat('%', #{chargeItemId}, '%')
and te.material_name like concat('%', #{materialName}, '%')
union all
select l.id as linkId, l.visit_kind as visitKind, l.mirror_row_id as mirrorRowId, l.alloc_qty as allocQty, ifnull(l.returned_qty, 0) as returnedQty, l.dept_batch_consume_entry_id as deptBatchConsumeEntryId, coalesce(nullif(trim(l.in_hospital_code), ''), nullif(trim(e.main_barcode), ''), nullif(trim(gzi.in_hospital_code), '')) as inHospitalCode, ifnull(l.confirm_status, 0) as confirmStatus, l.confirm_id as confirmId, c.confirm_no as confirmNo, in_bill.bill_no as inboundBillNo, out_bill.bill_no as outboundBillNo, th_bill.bill_no as returnGoodsBillNo, tk_bill.bill_no as returnDepotBillNo, ifnull(l.instant_io_audit_status, 0) as instantIoAuditStatus, l.instant_io_audit_by as instantIoAuditBy, l.instant_io_audit_time as instantIoAuditTime, c.confirm_by as confirmBy, c.confirm_time as confirmTime, h.create_time as consumeCreateTime, cast(h.audit_date as datetime) as consumeAuditDate, () as consumeAuditTime, h.consume_bill_no as consumeBillNo, null as consumeEntryId, e.material_id as materialId, e.material_name as materialName, e.unit_price as unitPrice, coalesce(l.alloc_qty, e.qty) as entryQty, case when e.unit_price is not null and coalesce(l.alloc_qty, e.qty) is not null then e.unit_price * coalesce(l.alloc_qty, e.qty) else e.amt end as amt, cast(e.supplier_id as char) as supplierId, sup.name as supplierName, e.batch_no as batchNo, as departmentId, d.name as departmentName, coalesce(nullif(trim(coalesce(inp.dept_name, outp.clinic_name)), ''), null) as orderingDeptName, coalesce(nullif(trim(coalesce(inp.exec_dept_name, outp.exec_dept_name)), ''), null) as execDeptName, coalesce(inp.patient_name, outp.patient_name) as patientName, coalesce(inp.inpatient_no, outp.outpatient_no) as visitNo, coalesce(inp.his_inpatient_charge_id, outp.his_outpatient_charge_id) as hisChargeId, coalesce(inp.charge_item_id, outp.charge_item_id) as chargeItemId, coalesce(inp.item_name, outp.item_name) as itemName, coalesce( nullif(trim(inp.spec_model), ''), nullif(trim(outp.spec_model), ''), nullif(trim(e.material_speci), ''), (select cm.speci from fd_material cm where cm.tenant_id = l.tenant_id and trim(cm.his_charge_item_id) = trim(coalesce(inp.charge_item_id, outp.charge_item_id)) and (cm.del_flag = 0 or cm.del_flag is null) order by cm.id limit 1) ) as itemSpec, coalesce( (select cm.model from fd_material cm where cm.tenant_id = l.tenant_id and trim(cm.his_charge_item_id) = trim(coalesce(inp.charge_item_id, outp.charge_item_id)) and (cm.del_flag = 0 or cm.del_flag is null) order by cm.id limit 1), e.material_model ) as itemModel, coalesce(nullif(trim(e.material_speci), ''), m.speci) as materialSpeci, coalesce(nullif(trim(e.material_model), ''), m.model) as materialModel, coalesce(nullif(trim(e.material_no), ''), e.batch_number, nullif(trim(gzi.material_no), ''), nullif(trim(gse2.batch_number), '')) as batchNumber, coalesce(e.begin_time, gzi.material_date, gse2.begin_time, goe2.begin_time) as productionDate, coalesce(e.end_time, goe2.end_time, gse2.end_time) as endTime, coalesce(nullif(trim(ff.factory_name), ''), null) as factoryName, m.register_no as registerNo from his_mirror_consume_link l inner join t_hc_ks_xh h on h.id = l.dept_batch_consume_id and h.tenant_id = l.tenant_id and ifnull(h.del_flag, 0) = 0 and ifnull(h.reverse_flag, 0) = 0 and h.bill_source = 'HIS_MIRROR_ROW_HIGH' and h.consume_bill_status = 2 inner join t_hc_ks_xh_entry e on e.id = l.dept_batch_consume_entry_id and ifnull(e.del_flag, 0) = 0 left join gz_dep_inventory gzi on gzi.id = l.gz_dep_inventory_id and gzi.tenant_id = l.tenant_id left join gz_shipment_entry gse2 on ifnull(gse2.del_flag, 0) != 1 and gse2.tenant_id = l.tenant_id and trim(ifnull(gse2.in_hospital_code, '')) = trim(coalesce(nullif(trim(l.in_hospital_code), ''), nullif(trim(e.main_barcode), ''), nullif(trim(e.sub_barcode), ''), nullif(trim(gzi.in_hospital_code), ''))) and trim(coalesce(nullif(trim(l.in_hospital_code), ''), nullif(trim(e.main_barcode), ''), nullif(trim(e.sub_barcode), ''), nullif(trim(gzi.in_hospital_code), ''))) != '' left join gz_order_entry goe2 on ifnull(goe2.del_flag, 0) != 1 and goe2.tenant_id = l.tenant_id and goe2.batch_no = coalesce(nullif(trim(gzi.batch_no), ''), nullif(trim(gse2.batch_no), ''), nullif(trim(e.batch_no), '')) left join fd_material m on m.id = e.material_id and m.tenant_id = l.tenant_id left join fd_factory ff on ff.factory_id = coalesce(e.material_factory_id, e.factory_id, m.factory_id) left join fd_department d on d.id = left join fd_supplier sup on sup.id = e.supplier_id and sup.tenant_id = l.tenant_id left join gz_high_consume_confirm c on c.id = l.confirm_id and c.tenant_id = l.tenant_id left join gz_high_consume_confirm_bill in_bill on in_bill.confirm_id = l.confirm_id and in_bill.tenant_id = l.tenant_id and in_bill.bill_type = 101 and ifnull(in_bill.del_flag, 0) = 0 and in_bill.supplier_id = cast(e.supplier_id as char) left join gz_high_consume_confirm_bill out_bill on out_bill.confirm_id = l.confirm_id and out_bill.tenant_id = l.tenant_id and out_bill.bill_type = 201 and ifnull(out_bill.del_flag, 0) = 0 and out_bill.supplier_id = cast(e.supplier_id as char) left join gz_high_consume_confirm_bill th_bill on th_bill.confirm_id = l.confirm_id and th_bill.tenant_id = l.tenant_id and th_bill.bill_type = 301 and ifnull(th_bill.del_flag, 0) = 0 and th_bill.supplier_id = cast(e.supplier_id as char) left join gz_high_consume_confirm_bill tk_bill on tk_bill.confirm_id = l.confirm_id and tk_bill.tenant_id = l.tenant_id and tk_bill.bill_type = 401 and ifnull(tk_bill.del_flag, 0) = 0 and tk_bill.supplier_id = cast(e.supplier_id as char) left join his_inpatient_charge_mirror inp on l.visit_kind = 'INPATIENT' and inp.id = l.mirror_row_id and inp.tenant_id = l.tenant_id left join his_outpatient_charge_mirror outp on l.visit_kind = 'OUTPATIENT' and outp.id = l.mirror_row_id and outp.tenant_id = l.tenant_id where l.tenant_id = #{tenantId} and ifnull(l.del_flag, 0) = 0 and l.gz_dep_inventory_id is not null and l.traceability_id is null and l.dept_batch_consume_id is not null
and = #{departmentId}
and exists ( select 1 from fd_department od where od.id = #{orderingDepartmentId} and od.tenant_id = l.tenant_id and ( (l.visit_kind = 'INPATIENT' and inp.id is not null and trim(od.his_id) = trim(inp.dept_code)) or (l.visit_kind = 'OUTPATIENT' and outp.id is not null and trim(od.his_id) = trim(outp.clinic_code)) ) )
and exists ( select 1 from fd_department xd where xd.id = #{execDepartmentId} and xd.tenant_id = l.tenant_id and trim(xd.his_id) = trim(coalesce(inp.exec_dept_id, outp.exec_dept_id)) )
and ifnull(l.confirm_status, 0) = #{confirmStatus}
and ifnull(l.confirm_status, 0) = 1 and ifnull(l.instant_io_audit_status, 0) = 1 and ifnull(l.returned_qty, 0) > 0 and th_bill.id is null and tk_bill.id is null
and ifnull(l.instant_io_audit_status, 0) = #{instantIoAuditStatus}
and () >= #{beginConsumeAuditTime}
and () <= #{endConsumeAuditTime}
and coalesce(inp.patient_name, outp.patient_name) like concat('%', #{patientName}, '%')
and coalesce(inp.inpatient_no, outp.outpatient_no) like concat('%', #{visitNo}, '%')
and ( (l.visit_kind = 'INPATIENT' and inp.his_inpatient_charge_id like concat('%', #{hisChargeId}, '%')) or (l.visit_kind = 'OUTPATIENT' and outp.his_outpatient_charge_id like concat('%', #{hisChargeId}, '%')) )
and coalesce(inp.charge_item_id, outp.charge_item_id) like concat('%', #{chargeItemId}, '%')
and e.material_name like concat('%', #{materialName}, '%')

mapper.select:
select l.id as linkId, l.visit_kind as visitKind, l.mirror_row_id as mirrorRowId, l.alloc_qty as allocQty, l.dept_batch_consume_entry_id as deptBatchConsumeEntryId, ifnull(l.confirm_status, 0) as confirmStatus, l.confirm_id as confirmId, ifnull(l.instant_io_audit_status, 0) as instantIoAuditStatus, t.create_time as consumeCreateTime, cast(t.audit_date as datetime) as consumeAuditDate, () as consumeAuditTime, te.id as consumeEntryId, te.material_id as materialId, te.material_name as materialName, te.charge_price as unitPrice, coalesce(l.alloc_qty, te.quantity) as entryQty, case when te.charge_price is not null and coalesce(l.alloc_qty, te.quantity) is not null then te.charge_price * coalesce(l.alloc_qty, te.quantity) else null end as amt, cast(te.supplier_id as char) as supplierId, sup.name as supplierName, te.batch_no as batchNo, null as batchNumber, null as beginTime, te.expiry_date as endTime, te.master_barcode as mainBarcode, te.secondary_barcode as subBarcode, te.specification as materialSpeci, te.model as materialModel, null as factoryId, as departmentId from his_mirror_consume_link l inner join gz_traceability t on t.id = l.traceability_id and t.tenant_id = l.tenant_id and ifnull(t.del_flag, 0) = 0 and t.trace_source = 'HIS_MIRROR_HIGH' and t.order_status = 2 inner join gz_traceability_entry te on te.id = l.traceability_entry_id and te.tenant_id = l.tenant_id and ifnull(te.del_flag, 0) = 0 left join fd_supplier sup on sup.id = te.supplier_id and sup.tenant_id = l.tenant_id where l.tenant_id = #{tenantId} and ifnull(l.del_flag, 0) = 0 and l.gz_dep_inventory_id is not null and l.traceability_id is not null and l.id in
#{id}
union all
select l.id as linkId, l.visit_kind as visitKind, l.mirror_row_id as mirrorRowId, l.alloc_qty as allocQty, l.dept_batch_consume_entry_id as deptBatchConsumeEntryId, ifnull(l.confirm_status, 0) as confirmStatus, l.confirm_id as confirmId, ifnull(l.instant_io_audit_status, 0) as instantIoAuditStatus, h.create_time as consumeCreateTime, cast(h.audit_date as datetime) as consumeAuditDate, () as consumeAuditTime, null as consumeEntryId, e.material_id as materialId, e.material_name as materialName, e.unit_price as unitPrice, coalesce(l.alloc_qty, e.qty) as entryQty, case when e.unit_price is not null and coalesce(l.alloc_qty, e.qty) is not null then e.unit_price * coalesce(l.alloc_qty, e.qty) else e.amt end as amt, cast(e.supplier_id as char) as supplierId, sup.name as supplierName, e.batch_no as batchNo, e.batch_number as batchNumber, e.begin_time as beginTime, e.end_time as endTime, e.main_barcode as mainBarcode, e.sub_barcode as subBarcode, e.material_speci as materialSpeci, e.material_model as materialModel, coalesce(e.material_factory_id, e.factory_id) as factoryId, as departmentId from his_mirror_consume_link l inner join t_hc_ks_xh h on h.id = l.dept_batch_consume_id and h.tenant_id = l.tenant_id and ifnull(h.del_flag, 0) = 0 and ifnull(h.reverse_flag, 0) = 0 and h.bill_source = 'HIS_MIRROR_ROW_HIGH' and h.consume_bill_status = 2 inner join t_hc_ks_xh_entry e on e.id = l.dept_batch_consume_entry_id and ifnull(e.del_flag, 0) = 0 left join fd_supplier sup on sup.id = e.supplier_id and sup.tenant_id = l.tenant_id where l.tenant_id = #{tenantId} and ifnull(l.del_flag, 0) = 0 and l.gz_dep_inventory_id is not null and l.traceability_id is null and l.dept_batch_consume_id is not null and l.id in
#{id}

mapper.insert:
insert into gz_high_consume_confirm (
    id, tenant_id, confirm_no, department_id, warehouse_id,
    confirm_time, confirm_by, period_begin, period_end, remark,
    del_flag, create_by, create_time
) values (
    #{id}, #{tenantId}, #{confirmNo}, #{departmentId}, #{warehouseId},
    #{confirmTime}, #{confirmBy}, #{periodBegin}, #{periodEnd}, #{remark},
    ifnull(#{delFlag}, 0), #{createBy}, #{createTime}
)

mapper.select:
select id, tenant_id as tenantId, confirm_id as confirmId, supplier_id as supplierId, bill_type as billType, stk_io_bill_id as stkIoBillId, bill_no as billNo from gz_high_consume_confirm_bill where tenant_id = #{tenantId} and ifnull(del_flag, 0) = 0 and confirm_id in
#{id}
order by confirm_id, supplier_id, bill_type
